<template >
    <panel 
    type="recentRecordings"
    header="Recent Recordings"
    @closePanel="closeRecentRecordings"
    >
      <div v-if="totalRecordings" id="all-recordings">
        <transition-group name="recordings">
          <library-item class="recording-item" v-for="(recording, index) in recordings" :key="recording._id" 
            :name=recording.name
            :url=recording.dataURL
            :created-timestamp=recording.recordingTime
            :id=recording._id
            :index=index
            :port="port"
            :recording-duration="recording.originalDuration"
            :encoding-format="recording.encodingFormat"
            @deleteRecording="deleteRecording"
            @downloadRecording="downloadRecording"
            @editRecording="editRecording"
          />
        </transition-group>
      </div>
      <transition name="no-recs">
      <div id="no-recordings" v-if="!totalRecordings">
          <div id="no-recordings-msg">
            No recordings found
          </div>
      </div>
      </transition>
  </panel>
</template>

<script>
import Panel from '@/components/common/Panel.vue'
import LibraryItem from './LibraryItem.vue'

export default {

  name: "RecentRecordings",
  props: {
    recentRecordings: {
        type: Array,
        required: true,
    }, 
    port: {
        required: true,
    },
  },
  components: {
    LibraryItem,
    Panel
  },

  data() {
    return {
      recordings: this.recentRecordings,
      totalRecordings: this.recentRecordings.length
    }
  },

  mounted() {
  },
  methods: {
    closeRecentRecordings(e) {
        this.$emit("closeRecentRecordings")
    },
    deleteRecording(data) {
      this.$store.dispatch('deleteRecording', {'id': data.id})
      this.recordings.splice(data.index, 1)
      this.totalRecordings -= 1
    },
    editRecording(id) {
      this.$emit("editRecording", id)
    },
    downloadRecording(id) {
      this.$store.dispatch('downloadRecording', {'id':  id})
    },
  },

};
</script>

<style scoped>
  
    /* transitions */
  .recordings-enter-from {
    opacity: 0;
    transform: scale(0.6);
  }
  .recordings-enter-active {
    transition: all 0.4s ease;
  }
  .recordings-leave-to {
    opacity: 0;
    transform: scale(0.6);
  }
  .recordings-leave-active {
    transition: all 0.4s ease;
    position: absolute; /* for move transition after item leaves */
  }
  .recordings-move {
    transition: all 0.8s ease;
  }

  #no-recordings-msg {
    font-size: 36px;
    width: 100%;
    text-align: center;
    margin-top: 30%;
    font-weight: 150;
  }


  .no-recs-enter-from {
    opacity: 0;
  }
  .no-recs-enter-active {
    transition: all 2s ease;
  }
</style>
