<template >
  <div id="audio-player-wrapper">
    <div :id="id" class="audio-player">
      <div class="audio-player-content" v-if="recordingLoaded && valid">
        <div class="controls">
        <div @click="seekOnClick" class="timeline" :class="{active_t: active}">
          <div class="progress-pointer" :class="{active_p: active}"></div>
          <div class="progress"></div>
        </div>
        <div class="volume-container">
          <div class="volume-button">
            <div class="volume icono-volumeMedium"></div>
          </div>
          <div class="volume-slider">
            <div class="volume-percentage"></div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
</template>

<script>

export default {
  name: "AudioPlayer",
  props: {
    url: {
        type: String,
        required: true,
    }, 
    id: {
        type: String,
        required: true,
    }, 
    valid: {
      type: Boolean,
      required: true
    },
    active: {
      type: Boolean,
      required: true
    },
    isPlaying: {
      type: Boolean,
      required: true
    }
  },
  components: {
  },
  mounted() {
      this.audio = new Audio(this.url)
      this.audio.onloadedmetadata = () => this.handleAudioAttributes()      
  },

  beforeDestroy() {
    this.stopPlaying()
  },

  methods: {
    handleAudioAttributes() {
      this.recordingDuration = this.getPrettyTime(this.audio.duration)
      this.recordingLoaded = true
      this.playerElement = document.getElementById(this.id)
    },

    seekOnClick(event) {
      let clickLocationOnTimeLine = event.offsetX
      const timeToSeek = clickLocationOnTimeLine / this.timeLineWidth * this.audio.duration;
      this.audio.currentTime = timeToSeek
      this.updateProgressBarPercent(this.audio.currentTime  / this.audio.duration * 100)
      this.updateCurrentTime()
    },

    playPause(event) {
      if (this.audio.paused) {
        this.startPlaying(event.target)
      }
      else {
        this.stopPlaying(event.target)
      }
    },

    startPlaying() {
      this.progressWatcher = setInterval(() => {
        this.checkProgress()
      }, 100)
      this.timeWatcher = setInterval(() =>{
        this.updateCurrentTime()
      }, 250)
      this.audio.play();
    },

    stopPlaying() {

      this.audio.pause();
      clearInterval(this.progressWatcher)
      clearInterval(this.timeWatcher)
    },

    checkProgress() {
      if (this.audio) {
        if (!this.playbackFinished) {
          let newPercent = this.audio.currentTime / this.audio.duration * 100
          this.updateProgressBarPercent(newPercent);
          this.$emit("setCurrentTime", this.audio.currentTime)
        }
        else {
          this.updateProgressBarPercent(0)
          this.playbackFinished = false
        }
        if (this.audio.currentTime == this.audio.duration) {
          this.stopPlaying()
          this.playbackFinished = true
          this.$emit("playbackFinished")
        }
      }
    },

    updateProgressBarPercent(value) {
      const progressBar = this.playerElement.querySelector(".progress");
      const progressPointer = this.playerElement.querySelector(".progress-pointer");
      progressBar.style.width = `${value}%`
      progressPointer.style.left = `${value}%`
    },

    updateCurrentTime() {
      let currentTime = this.getPrettyTime(this.audio.currentTime)
      this.playerElement.querySelector(".time .current").textContent = currentTime; 
    },

    getPrettyTime(time) {
      let seconds = parseInt(time);
      let minutes = parseInt(seconds / 60);
      seconds -= minutes * 60;
      return `${minutes}:${String(seconds % 60).padStart(2, 0)}`;
    },
    togglePlay() {
      if (this.isPlaying == true) {
        this.startPlaying()
      }
      else {
        this.stopPlaying()
      }
    }

  },
  data() {
    return {
      audio: null,
      recordingLoaded: false,
      recordingDuration: undefined,
      timeLineWidth: 350,
      playbackFinished: false,
      progressWatcher: null,
      playerElement: null,
    }
  },
  watch: {
    isPlaying: "togglePlay",
  }
};
</script>

