<template >
  <div @click="closePanel" class="panel-container">
    <div class="panel-content-container">
      <div class="panel-header">
        <div @click="closePanel" class="panel-exit">
          <svg-icon fill="#2D1E38" stroke="#2D1E38" class="panel-exit-icon" icon="arrow-down"/>
        </div>
        <div class="panel-header-text">{{ header }}</div>
      </div>
      <div class="panel-content">
        <slot />
      </div>
    </div>
</div>
</template>

<script>

import SvgIcon from '@/components/common/SvgIcon.vue'

export default {

  name: "Panel",
  props: {
    type: {
        type: String,
        required: true,
    }, 
    header: {
        type: String,
        required: true,
    },
  },
  components: {
    SvgIcon
  },

  data() {
    return {
    }
  },

  mounted() {
  },
  methods: {
    closePanel(e) {
      var exit = document.getElementsByClassName('panel-exit')[0];
      var container = document.getElementsByClassName('panel-container')[0];
      if (exit) 
        if (exit == e.target || exit.contains(e.target) || container == e.target) {
          this.$emit("closePanel")
        }
    },
  },

};
</script>

