<template>
  <div id="waveform-control-container">
      <waveform
      ref="wave"
      :active-sample="activeSample"
      :start="dynamicStart"
      :length="dynamicLength"
      :play="play"
      @newStartTime="setNewStartTime"
      @newDuration="setNewDuration" 
      @syncTime="syncTimeDataInDB"  
      @playbackComplete="playbackComplete"  
      />
      <waveform-actions
      :sample-start="dynamicStart"
      :sample-duration="dynamicLength"
      :is-playing="isPlaying"
      :active-sample="activeSample"
      @playPause="playPause"
      @zoomIn="$refs.wave.zoomIn()"
      @zoomOut="$refs.wave.zoomOut()"
      @skipForward="$refs.wave.skipForward()"
      @skipBack="$refs.wave.skipBack()"
      @reverse="reverse"
      @deleteRecording="deleteRecording"
      @downloadRecording="downloadRecording"
      @newStartTime="setNewStartTime"
      @newDuration="setNewDuration"
      />
  </div>

</template>
<script>

import Waveform from './Waveform.vue'
import WaveformActions from './WaveformActions.vue'


export default {
  name: "WaveformControl",
  props: {
    activeSample: {
      type: Object,
      required: true
    },
    },
  mounted() {
  },
  methods: {
    setNewStartTime(startValue, syncTime) {
      this.dynamicStart = parseFloat(startValue)
      if (syncTime == true) {
        this.syncTimeDataInDB()
      }
    },
    playPause() {
      if (this.isPlaying == true) {
        this.stopPlaying()
      }
      else {
        this.startPlaying()
      }
    },
    playbackComplete() {
      this.isPlaying = false
      this.play = false
    },

    stopPlaying() {
      this.play = false
      this.isPlaying = false
    },
    startPlaying() {
      this.play = true
      this.isPlaying = true
    },
    
    zoomIn() {
      return true
    },
    zoomOut() {
      return true
    },
    setNewDuration(durationValue, syncTime) {
      this.dynamicLength = parseFloat(durationValue)
      if (syncTime == true) {
        this.syncTimeDataInDB()
      }
    },
    skipForward() {
      return true
    },
    skipBack() {
      return true
    },
    reverse() {
      this.$store.dispatch('reverseAudio', {'id': this.activeSample.id})
    },
    syncTimeDataInDB() {
      this.$store.dispatch('syncSampleTimes', {'start': this.dynamicStart, 'length': this.dynamicLength, 'id': this.activeSample.id})
    },
    deleteRecording() {
      this.$store.dispatch('deleteRecording', {'id': this.activeSample.id})
    },
    downloadRecording() {
      this.$store.dispatch('downloadRecording', {'id': this.activeSample.id})
    },

  },
  data(){ 
    return {
        dynamicStart: this.activeSample.start, 
        dynamicLength: this.activeSample.length,
        isPlaying: false,
        play: false,
    }
  },
  components: {
    WaveformActions,
    Waveform
  },
  watch: {
  },
};
</script>

<style scoped>
 #waveform-control-container {
   height: 330px;
 }
</style>
