<template>
  <div id="sample">
    <svg-sprite/>
    <nav-bar 
    @showRecentRecordings="showRecentRecordings"
    @showSettings="showSettings"
    :is-beta="isBeta"
    />
    <div id="content-container" :class="containerSize">
        <recent-recordings
          v-if="recentRecordingView && recentRecordingsData"
          :recent-recordings="recentRecordingsData"
          :port="port"
          :key="recentRecordingsTime"
          @closeRecentRecordings="closeRecentRecordings"
          @editRecording="editRecording"
          />
        <news
        v-if="newsView && newsData"
        :news="newsData"
        @newsViewed="markNewsAsViewed"
        @closeNews="closeNews"
        />
        <settings
         v-if="settingsView && settingsData"
         :settings="settingsData"
        @updateSettings="updateSettings"
        @closeSettings="closeSettings"
        />
      <recording-control 
        v-if="initComplete && !sampleView"
      />
      <loader v-if="!initComplete"/>
      <sample-control
      v-if="showSampleView"
      :_key="this.$store.state.activeSampleKey"
      :active-sample="this.$store.state.activeSample"
      :options="waveform_options"
      :port="port"
      />
    </div>
    <footer-bar 
      :port="port"
      :show-notification="showNewsNotification"
      @showNews="showNews"
    />
  </div>
</template>

<script>
import NavBar from '@/components/NavBar.vue';
import RecentRecordings from '@/components/recent_recordings/RecentRecordings.vue'
import RecordingControl from '@/components/sample_interaction/RecordingControl.vue';
import SampleControl from '@/components/sample_interaction/SampleControl.vue';
import FooterBar from '@/components/FooterBar.vue';
import Loader from '@/components/common/Loader.vue';
import SvgSprite from '@/components/common/SvgSprite.vue';
import News from '@/components/news/News.vue';
import Settings from '@/components/Settings.vue'


export default {
  name: "App",
  async mounted() {
    window.addEventListener('DOMContentLoaded',() => {
      this.port.onMessage.addListener(request => this.handleRequest(request))
      this.port.postMessage({'message': 'init'})
    })
    this.$store.subscribe((mutation, state) => {
      switch(mutation.type) {
        case "setLooping":
          this.port.postMessage({"message": 'looping-state-status',
                                 "data": {'isLooping': mutation.payload}})
          break;
        case "setRecordingInProgress":
          if (mutation.payload == true) {
            this.port.postMessage({"message": "start-recording"});
          }
          else {
            this.port.postMessage({"message": "stop-recording"});
          }
          break;
      }
    }),
    this.$store.subscribeAction((action) => {
      const payload = action.payload
      switch(action.type) {
        case "newSampleName":
          this.port.postMessage({"message":"new-name", "data": {"id": payload.id, "name":  payload.name}})
          break;
        case "syncSampleTimes":
          this.port.postMessage({'message': 'sample-time-data', 
                        'data': {'start': payload.start, 
                                'length': payload.length,
                                'id': payload.id}})
          break;
        case "reverseAudio":
          this.port.postMessage({'message': 'generate-reversed-audio', 
                              'data': {'id': payload.id}})
          break;
        case "deleteRecording":
          this.port.postMessage({'message': 'delete-recording', 
                        'data': {'id': payload.id}})
          break;
        case "downloadRecording":
          this.port.postMessage({'message': 'download-recording', 
                             'data': {'id': payload.id}})
          break;
        case "refreshRecordingURL": 
          this.port.postMessage({"message": "refresh-url", "data": {"id": payload.id}})
          break;
      }
    }
    )
  },
  components: { 
    NavBar, 
    RecentRecordings,
    RecordingControl,
    SampleControl,
    Loader,
    SvgSprite,
    FooterBar,
    News,
    Settings,
  },
 
  watch: {
  },
  methods: {
    showRecentRecordings() {
      this.port.postMessage({'message':'load-recent-recordings'})     
      this.containerSize = "long-container"
      this.recentRecordingView = true
      this.closeNews(false)
      this.closeSettings(false)
      this.recentRecordingsData = undefined
    },
    showNews() {
      this.containerSize = "long-container"
      this.closeRecentRecordings(false)
      this.closeSettings(false)
      this.newsView = true

    },
    showSettings() {
      this.port.postMessage({'message':'load-settings'})
      this.containerSize = "long-container"
      this.closeRecentRecordings(false)
      this.closeNews(false)
      this.settingsView = true
    },
    closeRecentRecordings(reduceSize=true) {
      if (reduceSize)
        this.containerSize = "short"
      this.recentRecordingView = false
    },
    closeNews(reduceSize=true) {
      if (reduceSize)
        this.containerSize = "short"
      this.newsView = false
    },
    closeSettings(reduceSize=true) {
      if (reduceSize)
        this.containerSize = "short"
      this.settingsView = false
      this.settingsData = null
    },
    newRecording() {
      this.port.postMessage({"message": "new-recording"})
    },
    editRecording(id) {
      this.port.postMessage({"message": 'load-new-recording', "id": id})
      this.resetActiveSampleData()
    },
    async setActiveSampleData(request) {
      await this.$store.dispatch("newActiveSample", request.sample_data) 
    },
    resetActiveSampleData() {
      this.$store.dispatch("resetActiveSample")
    },
    markNewsAsViewed() {
      this.port.postMessage({"message": 'news-viewed'})
    },
    updateSettings(settingName, settingValue) {
      switch(settingName) {
        case "sample-rate": 
          this.port.postMessage({"message": "new-sample-rate", "data": {"value": settingValue}})
          break;
        case "recordings-to-keep":
          this.port.postMessage({"message": "new-recordings-to-keep-amount", "data": {"value": settingValue}})
          break;
        case "auto-trim":
          this.port.postMessage({"message": 'auto-trim-setting', "data": {"value": settingValue}});
          break;
        case "channels-to-record":
          this.port.postMessage({"message": "new-recorded-channels", "data": {"value": settingValue}})
          break;
        case "recording-format":
          this.port.postMessage({"message": "update-recording-format", "data": {"value": settingValue}})
          break;
        case "tab-title-as-name":
          this.port.postMessage({"message": "update-tab-title-as-name", "data": {"value": settingValue}})
          break;
      }

    },
    async handleRequest(request) {
      switch(request.message) {
        case "init-complete":
          this.$store.commit("waveConfig", request.waveform_options)
          this.$store.commit("init", request.state)
          await this.setActiveSampleData(request)
          this.sampleView = this.$store.state.sampleExists && !this.$store.state.recordingInProgress;
          this.newsData = request.news
          this.showNewsNotification = request.show_news_notification
          this.initComplete = true
          break
        case "recording-finished":
          await this.setActiveSampleData(request)
          this.containerSize = "short"
          this.sampleView = true;
          break
        case 'active-recording-deleted':
          this.resetActiveSampleData()
          this.sampleView = false
          break
        case 'recording-in-progress':
          this.resetActiveSampleData()
          this.closeRecentRecordings()
          this.closeNews()
          this.closeSettings()
          this.sampleView = false
          break;
        case 'recent-recordings-ready':
          this.recentRecordingsData = request.data
          this.recentRecordingsTime = request.time
          break;
        case 'new-recording-loaded':
          this.sampleView = false
          await this.setActiveSampleData(request)
          this.sampleView = true
          this.closeRecentRecordings()
          this.containerSize = "short"
          break;
        case 'reverse-recording-ready':
          this.$store.commit("setIsisPreparingReverse", false)
          await this.setActiveSampleData(request)
          break;
        case 'remove-news-notification':
          this.showNewsNotification = false;
          break;
        case 'settings-ready':
          this.settingsData = request.data
          break;
        case 'encoding-started':
          this.$store.commit("setIsEncoding", true)
          this.$store.commit("setEncodingStartTime", request.startTime)
          break;
        case 'encoding-finished':
          this.$store.commit("setIsEncoding", false)
          break;
        case 'reverse-started':
          this.$store.commit("setIsisPreparingReverse", true)
          this.$store.commit("setReverseStartTime", request.startTime)

      }
    },
    
  },
  data(){ return {
    waveform_options: [], // get from init
    port: chrome.runtime.connect({name: "port"}),
    initComplete: false,
    showRecording: true,
    recentRecordingView: false,
    containerSize: "long", 
    recentRecordingsData: undefined,
    recentRecordingsTime: null,
    newsView: false,
    settingsView: false,
    newsData: undefined,
    showNewsNotification: false,
    settingsData: undefined,
    sampleView: false,
    isBeta: false,
    state: {}
    }
  },
  computed: {
    showSampleView: function() {
      return this.sampleView && this.initComplete && this.$store.state.activeSample
    }
  }

};
</script>
<style scoped>
@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@100;200;300;400;500&display=swap');

  #content-container {
    display: flex;
  }

  #sample {
      width: 500px;
      max-height: 600px;
      font-family: 'Roboto', sans-serif;
      background: linear-gradient(180deg, #14002a -10%,#f6aaa6 60%,#ffffff 100%);

    }

  #sample input {
    font-family: 'Roboto', sans-serif !important; 
  }

  #content-container.long-container {
    max-height: 470px !important;
    min-height: 470px !important;
  }

</style>
