<template >
    <panel 
    type="settings"
    header="Preferences"
    @closePanel="closeSettings">  
    <div class="settings">
      <div class="setting recording-format">
        <div>Recording Format:</div>
          <select id="recording-format" name="recording-format" @change="handleRecordingFormat">
            <option :selected="'wav' == recordingFormat" value="wav">WAV</option>
            <option :selected="'mp3' == recordingFormat" value="mp3">MP3</option>
          </select>
      </div>
      <div class="setting channels">
        <div>Channels to record:</div>
        <div class="channels-slider">
          <input type="range" min="0" max="2" class="slider" v-model="channelsNum">
           <div class="ticks"><span>|</span><span>|</span><span>|</span></div>
           <div class="ticks-text"><span>Left</span><span>Left + Right</span><span>Right</span></div>
        </div>
      </div>
      <div class="setting recent-recordings">
        <div>Recent recordings to keep:</div>
          <select id="recent-recordings" name="recent-recordings" @change="handleRecordingsToKeep">
          <option :selected="0 == recordingsToKeep" value="0">0</option>
           <option :selected="5 == recordingsToKeep" value="5">5</option>
          <option :selected="10 == recordingsToKeep" value="10">10</option>
          <option :selected="20 == recordingsToKeep" value="20">20</option>
          <option :selected="30 == recordingsToKeep" value="30">30</option>
        </select>
      </div>
      <div class="setting auto-trim">
        <div>Auto trim recording edges:</div>
          <div class="auto-trim-toggle" name="auto-trim-toggle" @change="handleAutoTrim">
                <label class="switch"><input v-model="autoTrim" type="checkbox" />   
                 <div></div>
                </label>
          </div>
      </div>
      <div class="setting tab-title">
        <div>Use tab title as sample name:</div>
          <div class="tab-title-as-name-toggle" name="tab-title-as-name-toggle" @change="handleTabTitleAsName">
                <label class="switch"><input v-model="tabTitleAsName" type="checkbox" />   
                 <div></div>
                </label>
          </div>
      </div>
    </div>
  </panel>
</template>

<script>
import Panel from '@/components/common/Panel.vue'

export default {

  name: "Settings",
  props: {
    settings: {
      required: true,
      type: Object
    },
  },
  components: {
    Panel
  },
  computed: {
      channelsNum: {
        get() {
          if (this.numberOfChannels == 0) {
            return 0 // left
          }
          if (this.numberOfChannels == 1) {
            return 2 // right
          }
          if (this.numberOfChannels == 2) {
            return 1 // left + right
          }
          return 1
        },
        set(val) {
          if (val == 0) {
            this.numberOfChannels = 0 // left
          }
          if (val == 1) {
            this.numberOfChannels = 2 // left + right
          }
          if (val == 2) {
            this.numberOfChannels = 1 //  right
          }
          this.updateSetting("channels-to-record", this.numberOfChannels)
        }
      },
      autoTrim: {
        get() {
          return this.autoTrimActive
        },
        set(val) {
          this.autoTrimActive = val
        }
      },
      tabTitleAsName: {
        get() {
          return this.tabTitleAsNameActive
        },
        set(val) {
          this.tabTitleAsNameActive = val
        }
      }
  },
  data() {
    return {
      numberOfChannels: this.settings.recordingSettings.channelsToRecord,
      sampleRate: this.settings.recordingSettings.sampleRate,
      recordingsToKeep: this.settings.appSettings.recordingsToKeep,
      autoTrimActive: this.settings.appSettings.isAutoTrim,
      recordingFormat: this.settings.recordingSettings.recordingFormat,
      tabTitleAsNameActive: this.settings.appSettings.useTabTitleAsName,
    }
  },

  mounted() {
  },
  methods: {
    closeSettings() {
        this.$emit("closeSettings")
    },
    handleSamples(e) {
        this.sampleRate =  this._getSelectValue(e)
        this.updateSetting("sample-rate", this.sampleRate)
    },
    handleRecordingsToKeep(e) {
        this.recordingsToKeep = this._getSelectValue(e)
        this.updateSetting("recordings-to-keep", this.recordingsToKeep)
    },
    handleRecordingFormat(e) {
      this.recordingFormat = this._getSelectValue(e)
      this.updateSetting("recording-format", this.recordingFormat)
    },
    handleAutoTrim() {
      this.updateSetting("auto-trim", this.autoTrim)
    },
    handleTabTitleAsName() {
      this.updateSetting("tab-title-as-name", this.tabTitleAsName)
    },
    updateSetting(settingName, settingValue) {
      this.$emit("updateSettings", settingName, settingValue)
    },
    _getSelectValue(e) {
      if(e.target.options.selectedIndex > -1) {
          return e.target.options[e.target.options.selectedIndex].value
      }
    },
  },

};
</script>

