<template >
  <div id="recording-control-container">
    <div id="recording-control">
        <div @click="startRecording" class="recording-control-item" 
        :class="{active : this.$store.state.recordingInProgress}" id="start-recording" 
        v-tooltip.left="{content: 'Start recording',
                         show: this.$store.state.showTutorial,
                         trigger: 'manual'

                         }">
        </div>
        <div @click="stopRecording" class="recording-control-item" id="stop-recording"
        v-tooltip.right="{content: 'Stop recording',
                    show: this.$store.state.showTutorial,
                    trigger: 'manual'
                    }">
        </div>
    </div>
</div>
</template>

<script>

export default {
  name: "RecordingControl",
  props: { 
    },

  mounted() {
  },
  methods: {
      startRecording() {
          this.$store.commit("setRecordingInProgress", true)
      },
      stopRecording() {
          this.$store.commit("setRecordingInProgress", false)
      },

  },
  data() {
    return {
        recordingInProgress: this.$store.state.recordingInProgress
    }
  },
};
</script>

