import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)


const checkSampleExists = async function(path) {
  try {
    const response = await fetch(path)
    return response.ok
  }
  catch(error) {
    return  false;
  }
}

const store = new Vuex.Store({
  state: {
    recordingInProgress:null,
    isLooping:null,
    currentNewsVersion:null,
    isRecordingMode:null,
    showTutorial:false,
    activeSampleKey: null,
    sampleExists: false,
    isEncoding: false,
    encodingStartTime: null,
    isPreparingReverse: false,

  },

  mutations: {
    init(state, dbState) {
      state.recordingInProgress = dbState.recordingInProgress
      state.isLooping = dbState.isLooping
      state.currentNewsVersion = dbState.currentNewsVersion
      state.isRecordingMode = dbState.isRecordingMode
    },
    setLooping(state, value) {
      state.isLooping = value
    },
    setRecordingInProgress(state, value) {
      state.recordingInProgress = value
    },
    setShowTutorial(state, value) {
      state.showTutorial = value
    },
    newActiveSample(state, value) {
      state.activeSampleKey = value
    },
    setActiveSampleKey(state, value) {
      state.activeSampleKey = value
    },
    setSampleExists(state, value) {
      state.sampleExists = value
    },
    setActiveSample(state, value) {
      state.activeSample = value
    },
    waveConfig(state, data) {
      state.waveConfig = data
    },
    setIsEncoding(state, value) {
      state.isEncoding = value
    },
    setEncodingStartTime(state, value) {
      state.encodingStartTime = value
    },
    setIsisPreparingReverse(state, value) {
      state.isPreparingReverse = value
    },
    setReverseStartTime(state, value) {
      state.reverseStartTime = value
    },
  },
  actions: {
    setLooping(context, value) {
      context.commit("setLooping", value)
    },
    async newActiveSample(context, sampleData) {
      context.commit("setActiveSample", sampleData)
      context.commit("setActiveSampleKey", sampleData.path)
      const sampleExists = await checkSampleExists(sampleData.path)
      context.commit("setSampleExists", sampleExists)
    },
    resetActiveSample(context) {
      context.commit("setActiveSample", undefined)
      context.commit("setActiveSampleKey", undefined)
      context.commit("setSampleExists", false)
    },
    // Event bus
    newSampleName(context) {},
    syncSampleTimes(context) {},
    reverseAudio(context) {},
    deleteRecording(context) {},
    downloadRecording(context) {},
    refreshRecordingURL(conext) {},

  }
})

export default store;