<template>
  <div id="waveform-actions-container">
    <div id="waveform-actions">
        <div id="time-config">
            <div id="sample-start">
                <label>Sample start:</label>
                <input id="sample-start-input" min="0" :max="activeSample.originalDuration" step="0.2" v-model="start" type="number" maxlength="3"/>
                <spinner @spinnerClick="handleStartSpinner" id="spinner-start"/>
            </div>
            <div id="sample-length">
                <label>Sample length:</label>
                <input id="sample-length-input" min="0.2" :max="activeSample.originalDuration - sampleStart" step="0.2" v-model="duration" type="number"/>
                <spinner @spinnerClick="handleLengthSpinner" id="spinner-end"/>
            </div>
        </div>
        <div id="zoom-config">
            <div @click="zoomIn" id="zoomin">
                <svg-icon stroke="#FFE1E1" icon="zoom-in"/>
            </div>
            <div @click="zoomOut" id="zoomout">
                <svg-icon stroke="#FFE1E1"  icon="zoom-out"/>
            </div>
        </div>
        <div id="sample-actions">
            <div @click="downloadRecording" id="download">
                <svg-icon v-if="!shouldShowDownloadLoading" fill="#FFE1E1" stroke="#FFE1E1" icon="download"/>
                <wheel-loader size="20px" color="#FFE1E1" v-else/>
            </div>
            <div @click="deleteRecording" id="discard">
                 <svg-icon fill="#FFE1E1" stroke="#FFE1E1" icon="delete-recording" />
            </div>
        </div>
    </div>
    <div id="playback-actions">
            <div @click="loop" class="action-item" :class="{ active: isLooping}" id="loop"
            v-tooltip.bottom="{content: 'Toggle sample loop',
                    show: this.$store.state.showTutorial,
                    trigger: 'manual'
            }"
            
            >
                <svg-icon stroke="#2D1E38" icon="repeat"/>
            </div>
            <div @click="skipBack" class="action-item" id="back">
                <svg-icon icon="skip-back" stroke="#2D1E38"/>
            </div>
            <div @click="playPause" class="action-item" id="playpause"> 
                <svg-icon v-if="!isPlaying" icon="play" fill="white" stroke="white"/>
                <svg-icon v-else icon="pause" fill="white" stroke="white"/>
            </div>
            <div @click="skipForward" class="action-item" id="forward">
                <svg-icon stroke="#2D1E38" icon="skip-forward"/>
            </div>


            <div @click="reverse" class="action-item" :class="{ active: shouldShowReversed || shouldShowReverseLoading}" id="reverse"
            v-tooltip.bottom="{content: 'Toggle sample reverse',
                    show: this.$store.state.showTutorial,
                    trigger: 'manual'
            }"
            >
                <svg-icon v-if="!shouldShowReverseLoading" stroke="#2D1E38" icon="reverse"/>
                <div class="reverse-loader" v-else>
                    <wheel-loader size="25px" color="#2D1E38"/>
                </div>
            </div>
        </div>
    </div>
</template>

<script>

import SvgIcon from '@/components/common/SvgIcon.vue'
import Spinner from '@/components/common/Spinner.vue'
import WheelLoader from '@/components/common/WheelLoader.vue'


export default {
  name: "WaveformActions",
  props: {
      activeSample: {
          required: true,
          type: Object
      },
      sampleStart: {
          type: Number,
          required: true,
      },
      sampleDuration: {
          type: Number,
          required: true,
      },
      isPlaying: {
          type: Boolean,
          default: false,
      },
  },
  components: {
      SvgIcon,
      Spinner,
      WheelLoader,
  },
  mounted() {
  },
  computed: {
      start: {
          get: function () {
              return this.sampleStart.toPrecision(3)
            },
          set: function(value) {
              value = parseFloat(value)
              let end = parseFloat(this.start) + parseFloat(this.duration)
              if (value >= 0 && value <= end) {
                this.$emit('newStartTime', value, true)
                return value
              }
          }
      },
      duration: {
          get: function () {
              return this.sampleDuration.toPrecision(3)
            },
          set: function(value) {
            value = parseFloat(value)
            if (value > 0.05 && value <= this.activeSample.originalDuration - this.start) {
                this.$emit('newDuration', value, true)
                return value
            }
          }
      },
  },
  methods: {
      handleStartSpinner(spinnerState) {
          let sampleStartInput = document.getElementById("sample-start-input")
          let start = parseFloat(this.start)
          let duration = parseFloat(this.duration)
          let end = start + duration 
          if (spinnerState == "up") {
              if (start + this.incrementValue <= end) 
              {
              this.handleSpinner(sampleStartInput, this.incrementValue)
              }
          }
          else {
              if (this.start - this.incrementValue >= 0) {
                this.handleSpinner(sampleStartInput, -this.incrementValue)
            }
          }  
      },

      handleLengthSpinner(spinnerState) {
          let sampleLengthInput = document.getElementById("sample-length-input")
          let start = parseFloat(this.start)
          let duration = parseFloat(this.duration)
          let end = start + duration 
          if (spinnerState == "up") {
              if (duration + this.incrementValue <= this.activeSample.originalDuration - start) {
                this.handleSpinner(sampleLengthInput, this.incrementValue)
              }
          }
          else {
              if (duration - this.incrementValue >= 0.05) {
               this.handleSpinner(sampleLengthInput, -this.incrementValue)
              }
          }     
      },
      handleSpinner(input, value) {
          input.value = parseFloat(input.value) + value
          input.dispatchEvent(new Event('input'));

      },
      toggleTutorial() {
        this.showTutorial = this.tutorial
      },

      playPause() {
          this.$emit('playPause')
      },
      zoomIn() {
          this.$emit('zoomIn')
      },
      zoomOut() {
          this.$emit('zoomOut')
      },
      skipForward() {
          this.$emit('skipForward')
      },
      skipBack() {
          this.$emit('skipBack')
      },
      downloadRecording() {
        this.$emit("downloadRecording");
      },
      deleteRecording() {
        this.$emit("deleteRecording");
      },
      loop() {
          if (this.isLooping == true) {
              this.isLooping = false
          }
          else {
              this.isLooping = true
          }
          this.$store.commit('setLooping', this.isLooping)
      },
      reverse() {
          if (this.isReversed == true) {
              this.isReversed = false
              setTimeout(() => {this.shouldShowReversed = false}, 500)

          }
          else {
              this.isReversed = true
              this.shouldShowReversed = true
          }
          this.$emit('reverse', this.isReversed)
      }

  },
  watch: {
    '$store.state.isEncoding': function() {
        if (this.$store.state.isEncoding == true) {
            setInterval(() => {
                const now = Date.now()
                if(now - this.$store.state.encodingStartTime > 200) {
                    if (this.$store.state.isEncoding) {
                        this.shouldShowDownloadLoading = true
                    }
                }
            }, 300)
        }
        this.shouldShowDownloadLoading = false;
    },
    '$store.state.isPreparingReverse': function() {
    if (this.$store.state.isPreparingReverse == true) {
        setInterval(() => {
            const now = Date.now()
            if(now - this.$store.state.reverseStartTime > 100) {
                if (this.$store.state.isPreparingReverse) {
                    this.shouldShowReverseLoading = true
                }
            }
        }, 300)
    }
    this.shouldShowReverseLoading = false;
    },
  },
  data(){ 
      return {
          isLooping: this.$store.state.isLooping,
          isReversed: this.activeSample.isReversed,
          incrementValue: 0.2,
          shouldShowDownloadLoading: false,
          shouldShowReverseLoading: false,
          shouldShowReversed: this.isReversed,
      }
  },
};
</script>

