<template>
  <div id="waveform-container">
      <div id="waveform"></div>
      <div id="wave-timeline"></div>
  </div>

</template>
<script>

import WaveSurfer from 'wavesurfer.js';
import Regions from 'wavesurfer.js/dist/plugin/wavesurfer.regions.js'
import Cursor from "wavesurfer.js/dist/plugin/wavesurfer.cursor";
import Timeline from "wavesurfer.js/dist/plugin/wavesurfer.timeline";
import {formatTimeCallback, timeInterval, primaryLabelInterval, secondaryLabelInterval} from "@/utils/timeline-formatting.js";


export default {
  name: "Waveform",
  props: {
    activeSample: {
      type: Object,
      required: true
    },
    start: {
      required: true
    },
    length: {
      required: true
    },
    play: {
        required: true
    }, 
    },
  mounted() {
    this.initWavesurfer();
  },
  methods: {
      setURL() {
          if (this.activeSample.path) {
            this.url = this.activeSample.path
            this.updateWave()
          }
          
      },
      initWavesurfer() {
        this.waveConfig.plugins = this.getPluginData()
        this.waveConfig.zoomValue = 0
        this.wavesurfer = WaveSurfer.create(this.waveConfig);
        this.updateWave()
        this.registerWaveEvents()
      },
      updateWave() {
          if (this.wavesurfer)
          {
              this.wavesurfer.load(this.url);
          } 
      },
      getPluginData() {
         return [Regions.create({createRegion: true}), 
                 this.getCursorPlugin(),
                 this.getTimelinePlugin(),
                 ]
      },
      
      getTimelinePlugin() {
          return Timeline.create({container: "#wave-timeline",
                           formatTimeCallback: formatTimeCallback,
                           timeInterval: timeInterval,
                           primaryLabelInterval: primaryLabelInterval,
                           secondaryLabelInterval: secondaryLabelInterval,
                           primaryColor: '#2D1E38',
                           primaryFontColor: '#2D1E38'
          })
      },
      getCursorPlugin() {
          return Cursor.create({
            showTime: true,
            opacity: 1,
            customShowTimeStyle: {
               'background-color': '#000',
                color: 'white',
                padding: '2px',
                'font-size': '10px',
                position: 'relative',

            }
          })
      },
      initRegionsPlugin() {
        if (Object.keys(this.wavesurfer.regions.list).length == 0) {
        this.wavesurfer.addRegion({
                        start: this.sampleStartTime,
                        id: this.regionId,
                        end: this.sampleStartTime + this.sampleLength,
                        color: this.waveConfig.selectionColor,
        })
        this.updateTimeData()
        }
      },
      
      registerWaveEvents() {
          this.wavesurfer.on('ready', () => {
            this.setStartAndLength()
            this.initRegionsPlugin()
          })
          this.wavesurfer.on('region-mouseenter', function() {
              let start = document.querySelector('.wavesurfer-handle-start');
              let end = document.querySelector('.wavesurfer-handle-end');
              start.style.setProperty("display", "inline-block", "important");
              end.style.setProperty("display", "inline-block", "important");
          })
          this.wavesurfer.on('region-mouseleave', function() {
              let start = document.querySelector('.wavesurfer-handle-start');
              let end = document.querySelector('.wavesurfer-handle-end');
              start.style.setProperty("display", "none", "important");
              end.style.setProperty("display", "none", "important");
              
          })
          this.wavesurfer.on("seek", (cursorLocation) => {
             this.startTime = cursorLocation * this.totalRecordingDuration
          })


          this.wavesurfer.on('pause', () => {
            var region = this.getRegion()
            let currentTime = this.wavesurfer.getCurrentTime()
            this.cursorLocation = currentTime / this.totalRecordingDuration
            if (Math.abs(currentTime - region.end) > 0.5)
            {
              this.startTime = currentTime;
            }
            else {
              this.resetStartTime()
              if (this.$store.state.isLooping) {
                this.playPause()
              }
              else {
                this.$emit('playbackComplete')
              }
              
            }
            
          })
          this.wavesurfer.on('region-update-end', () => {
            this.resetStartTime()
            this.$emit("syncTime")
          })
          this.wavesurfer.on('region-updated', () => {
            this.updateTimeData()
          })
      },
      playPause() {
        let regions = this.wavesurfer.regions.list
        let region = regions[this.regionId]
        if (this.play === true) {
          let start = this.getStartTime(region)
          let end = this.getEndTime(region)
          this.wavesurfer.play(start, end)
          }
        else if (this.play === false) {
          this.wavesurfer.pause()
        }
      },
      getStartTime(region) {
        if (this.startTime > region.start) {
            return this.startTime
        }
        else if (this.startTime === 0) {
            return region.start
        }
        return region.start
      },
      getEndTime(region) {
        return region.end
      },
      resetStartTime() {
        this.startTime = 0
      },
      getRegion() {
        let regions = this.wavesurfer.regions.list
        return regions[this.regionId]
      },
      updateTimeData() {
        let region = this.getRegion()
        this.sampleStartTime = region.start
        this.sampleLength = region.end - region.start
        this.cursorLocation = region.start / this.totalRecordingDuration
        this.wavesurfer.seekAndCenter(this.cursorLocation)
        this.$emit('newStartTime', this.sampleStartTime, false)
        this.$emit('newDuration', this.sampleLength, false)

      },
      setNewStartTime() {
        let region = this.getRegion()
        region.update({start: this.start})
      },
      setNewDuration() {
        let region = this.getRegion()
        let end = region.start + parseFloat(this.length)
        region.update({'end': end})
      },
      setStartAndLength() {
        this.totalRecordingDuration = this.wavesurfer.getDuration()
        if (this.start >= 0) {
          this.sampleStartTime = this.start
        }
        else {
          this.sampleStartTime = 0.5
        }
        if (this.length) {
          this.sampleLength = this.length
        }
        else {
          this.sampleLength = this.wavesurfer.getDuration() - 1
        }
      },
      zoomIn() {
        let potenialZoom = Math.ceil(this.wavesurfer.params.minPxPerSec * this.sampleLength)
        if (potenialZoom <= 300) {
          this.waveConfig.zoomValue += 300
        }
        else {
          this.waveConfig.zoomValue += 50
        }
        this.wavesurfer.zoom(this.waveConfig.zoomValue)
      },
      zoomOut() {
        if (this.waveConfig.zoomValue - 50 >= 0) {
          this.waveConfig.zoomValue -= 50
        }
        this.wavesurfer.zoom(this.waveConfig.zoomValue)
      },
      skipForward() {
        let regions = this.wavesurfer.regions.list
        let region = regions[this.regionId]
        let maxCursorPosition = region.end / this.totalRecordingDuration
        if (this.cursorLocation + 0.1 >= maxCursorPosition) {
          this.cursorLocation = maxCursorPosition
        }
        else {
          this.cursorLocation += 0.1
        }
        this.startTime = this.cursorLocation * this.totalRecordingDuration
        this.wavesurfer.seekAndCenter(this.cursorLocation )
        
      },
      skipBack() {
        let regions = this.wavesurfer.regions.list
        let region = regions[this.regionId]
        let minCursorPosition = region.start / this.totalRecordingDuration
        if (this.cursorLocation - 0.1 <= minCursorPosition)
          this.cursorLocation = minCursorPosition
        else {
          this.cursorLocation -= 0.1
        }
        this.startTime = this.cursorLocation * this.totalRecordingDuration
        this.wavesurfer.seekAndCenter(this.cursorLocation)
      },
  },
  data(){ 
      return {
      url: this.activeSample.path,
      wavesurfer: null,
      has_region: false,
      waveConfig: this.$store.state.waveConfig,
      regionId: 'main-region',
      startTime: this.start,
      isPlaying: false,
      sampleStartTime: this.start,
      sampleLength: 0,
      totalRecordingDuration: 0,
      cursorLocation: 0,
    }
  },
  components: {
  },
  watch: {
      activeSample: {
        handler() {
          this.setURL()
        },
        deep: true
      },
      start: 'setNewStartTime',
      length: 'setNewDuration',
      play: 'playPause',
  },
};
</script>

<style scoped>
    #waveform-container {
        width: 90vw;
        max-width: 90vw;
        height: 240px;
        margin-top: 80px;

    }

    #waveform {
        position: relative;
        border: 1px solid #2D1E38;
        border-radius: 3px;
        background-color: #2D1E38;
        scrollbar-color: red yellow;

    } 

</style>
