
<template>
  <svg :id="id" :class="icon">
    <use :xlink:href="`#${icon}`" />
  </svg>
</template>

<script>
export default {
  name: 'SvgIcon',
  props: {
    icon: {
      type: String,
      required: true,
    },
    stroke: {
      type: String,
      default: "#363636",
    },
    width: {
      default: "20px",

    },
    height: {
      default: "20px",
    },
    fill: {
      default: "none"
    },
    id: {
      defaut: 'none'
    },

  },
  mounted() {
    let x = document.querySelector(`svg.${this.icon}`)
    x.style.stroke = this.stroke
    x.style.fill = this.fill
    
  },
  watch: {
    stroke: function() {
    }
  }
}
</script>

<style>
svg.icon {
  stroke: black;
  fill: none;
  height: 50px;
  vertical-align: middle;
  width: 50px;
}
</style>