<template>
  <div id="sample-name-container">
    <div id="sample-name">
        <div id="label">Name your sample</div>
        <input :placeholder="getPlaceholderValue()" 
        v-model="name" id="sample-name-value" type="text"/>
    </div>
    </div>
</template>

<script>

export default {
  name: "SampleName",
  props: {
      sampleCurrentName: {
          required: true,
      },
      id: {
          required: true,
      },
  },
  mounted() {
  },
  methods: {
      handleName() {
          if (this.validName) {
            this.isValid = true
          }
          else {
              this.isValid = false
          }
          this.$store.dispatch("newSampleName", {"name": this.name, "id": this.id})
      },
      getPlaceholderValue() {
          if (this.placeholderName) {
              return this.placeholderName
          }
          return ""
      },
  },
  data(){ 
      return {
          validName: this.sampleCurrentName,
          placeholderName: this.sampleCurrentName,
          isValid: false,
          timeout: undefined
      }
  },
  computed: {
     name: {
        get() {
          return this.validName
        },
        set(val) {
          this.isValid = false
          if (this.timeout) 
            clearTimeout(this.timeout)
          this.timeout = setTimeout(() => {
            document.getElementById("sample-name-value").blur()
            this.validName = val
            if (this.validName.length > 0) {
                this.placeholderName = this.validName
            }
          }, 2000)
        }
      }
    },
   watch:{
       validName: "handleName"
   }

};

</script>

