<template >
  <div @mouseenter="activate" 
       @mouseleave="deactivate" class="library-item-container" :class="{first: index == 0,}">
    <div v-if="validURL" class="library-item">
      <div class="play-pause" :class="{playing: isPlaying}">
        <div @click="playAudio" class="play" v-if="!isPlaying"></div>
        <div @click="pauseAudio" class="pause" v-if="isPlaying"></div>
      </div>
      <div class="sample-details">
        <div class="name">{{ name }}.{{ encodingFormat }}</div>
        <div class="time-details">
          <div class="progress" v-if="isActive">{{ currentTime }}</div>
          <div class="slash" v-if="isActive">/</div>
          <div class="length">{{ recordingLength }}</div>
        </div>
      </div>
      <div v-if="isActive" class="controls">
          <div v-if="!shouldShowLoading" @click="downloadRecording" id="download"></div>
          <wheel-loader id="downloadLoader" v-else size="17px" color="#FFE1E1"/>

          <div @click="deleteRecording" id="delete"></div>
          <div @click="editRecording" id="edit"></div>
        </div>

      <div class="break"></div>
      <div class="player" :class="{active: isActive}">
      <audio-player 
      :url="urlToLoad" 
      :id="id" 
      :valid="validURL"
      :active="isActive"
      :is-playing="isPlaying"
      @playbackFinished="pauseAudio"
      @setCurrentTime="setCurrentTime"
      />
      </div>
    </div>
    <loader v-else/>
  </div>
</template>

<script>

import AudioPlayer from '@/components/recent_recordings/AudioPlayer.vue'
import Loader from '@/components/common/Loader.vue'
import WheelLoader from '@/components/common/WheelLoader.vue'


export default {
  name: "LibraryItem",
  props: {
    name: {
        type: String,
        required: true,
    }, 
    url: {
        type: String,
        required: true,
    }, 
    createdTimestamp: {
        type: Number,
        required: true,
    }, 
    id: {
        type: String,
        required: true,
    }, 
    index: {
        type: Number,
        required: true,
    }, 
    port: {
      required: true
    },
    recordingDuration: {
      required: true
    },
    encodingFormat: {
      default: 'wav',
      required: true
    },

  },

  async mounted() {
    this.port.onMessage.addListener(request => this.handleRequest(request))
    this.validURL = await this.checkRecordingExists()
    if (!this.validURL) {
      this.$store.dispatch("refreshRecordingURL", {"id": this.id})
    }
  },

  methods: {
    handleRequest(request) {
      switch(request.message) {
        case "new-url-ready":
          this.urlToLoad = request.url
          this.validURL = true
          break
      }
    },

    downloadRecording() {
      this.$emit("downloadRecording", this.id)
    },
    deleteRecording() {
      this.$emit('deleteRecording', {index: this.index, id: this.id})
    },
    editRecording() {
      this.$emit('editRecording', this.id)
    },
    async checkRecordingExists() {
      try {
        const response = await fetch(this.url)
        return response.ok
      }
      catch(error) {
        return false
      }
    },
    getPrettyTime(time) {
      let seconds = parseInt(time);
      let minutes = parseInt(seconds / 60);
      seconds -= minutes * 60;
      return `${minutes}:${String(seconds % 60).padStart(2, 0)}`;
    },
    activate() {
      this.deacticateOnPlayFinish = false
      this.isActive = true
    },
    deactivate() {
      if (!this.isPlaying)
        this.isActive = true
      else {
         this.deacticateOnPlayFinish = true;
      }
     
    },
    playAudio() {
      this.isPlaying = true;
    },
    pauseAudio() {
      this.isPlaying = false;
      if (this.deacticateOnPlayFinish) {
        this.deactivate()
      }
    },
    setCurrentTime(time) {
       this.currentTime = this.getPrettyTime(time)
    },
  },
  data() {
    return {
      createdTime: new Date(this.createdTimestamp * 1000),
      validURL: false,
      urlToLoad: this.url,
      isPlaying: false,
      recordingLength: this.getPrettyTime(Math.ceil(this.recordingDuration)),
      isActive: false,
      currentTime: this.getPrettyTime(0),
      deacticateOnPlayFinish: false,
      shouldShowLoading: false,

    }
  },
  watch: {
    '$store.state.isEncoding': function() {
        if (this.$store.state.isEncoding == true) {
            setInterval(() => {
                const now = Date.now()
                if(now - this.$store.state.encodingStartTime > 200) {
                    if (this.$store.state.isEncoding) {
                        this.shouldShowLoading = true
                    }
                }
            }, 300)
        }
        this.shouldShowLoading = false;
    }
  },
  components: {
    AudioPlayer,
    Loader,
    WheelLoader,
  }
};
</script>

<style scoped>

.library-item-container {
  margin-bottom: 10px;
  margin-top: 2px;
  width: 450px;
  height: 70px;
  background-color: #FFF5F5;
  transition: height 0.5s, background-color 0.1s;
  display: flex;
  flex-direction: row;
  align-items: center;
  align-content: center;
}

.library-item-container:hover {
  height: 110px;
  background-color: #FFDCDC;
}

.library-item {
  margin-top: 15px;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  align-content: center;
}

.player {
    display: flex;
    align-items: center;
    margin-left: 57px;
    margin-top: 5px;
}


.break {
  flex-basis: 100%;
  height: 0;
}

.first {
  border-top-right-radius: 25px;
}

.controls div {
  width: 25px;
  height: 25px;
  background-color: #14002A;
  border-radius: 100%;
  cursor: pointer;
  margin-left: 5px;
}

.controls {
  display: flex;
  flex-direction: row;
  margin-left: auto;
  margin-right: 15px;
  margin-top: -10px;
  align-content: center;


}

.sample-details {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: flex-start;
  margin-left: 15px;

}

.time-details {
  display: flex;
  flex-direction: row;
}

.slash {
  margin-left: 2px;
  margin-right: 2px;
}

.name {
    font-weight: 400;
    font-size: 15px;
    letter-spacing: 0.4px;
    color: #14002A;
    margin-bottom: 2px;
}

#download {
  background-image: url("~@/assets/icons/download.svg");
  background-size: 55% !important;
  background-repeat: no-repeat;
  background-position: center;
}

#downloadLoader {
  position: relative;
  margin-left: auto;
  margin-right: auto;
}

#delete {
  background-image: url("~@/assets/icons/delete-recording.svg");
  background-size: 55% !important;
  background-repeat: no-repeat;
  background-position: center;
}

#edit {
  background-image: url("~@/assets/icons/edit-recording.svg");
  background-size: 50% !important;
  background-repeat: no-repeat;
  background-position: center;
}

.play-pause {
  width: 35px;
  height: 35px;
  border-radius: 100%;
  margin-left: 15px;
  cursor: pointer;
  display: flex;
  justify-content: center;
  align-items: center;
  background-image: linear-gradient(-10deg,
                                    #14002a 20%,
                                    #f6aaa6 80%
                                    );
  background-position: right;
  background-size: 2000%;
  transition: background-size 1.5s;
}

.play-pause:hover {
  background-size: 100%;
}

.playing {
  background-size: 100%;
}

.play {
  background-size: 100%;
  height: 25px;
  width: 25px;
  background-repeat: no-repeat;
  background-image: url("~@/assets/icons/play-light.svg");
  
}

.pause {
  background-size: 100%;
  height: 25px;
  width: 25px;
  background-repeat: no-repeat;
  background-image: url("~@/assets/icons/pause-light.svg");
}

 /deep/ .wheel-loader {
  margin-left: 2.5px;
  margin-top: 2.5px;
}

</style>
